    "line": 76,
    "severity": "critical",
    "description": "isFeatureAllowedForScope does not handle undefined scope field. Per the documentation, features without a scope field should be allowed for all scopes. Currently it will crash when calling .includes() on undefined.",
    "fix_patch": "--- a/packages/features/feature-opt-in/config.ts
+++ b/packages/features/feature-opt-in/config.ts
@@ -73,5 +73,5 @@
 export function isFeatureAllowedForScope(slug: string, scope: OptInFeatureScope): boolean {
   const config = getOptInFeatureConfig(slug);
   if (!config) return false;
-  return config.scope.includes(scope);
+  return !config.scope || config.scope.includes(scope);
 }
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 205,
    "severity": "critical",
    "description": "listFeaturesForUser filter is inverted. The comment states it should return features that are 'globally enabled', but the filter returns features where globalEnabled is false (!state.globalEnabled). This contradicts the documented behavior and the logic used in listFeaturesForTeam (line 240) which correctly filters for globalEnabled.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -203,5 +203,5 @@
     });

-    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => !state.globalEnabled);
+    return featureIds.map((featureId) => resolvedStates[featureId]).filter((state) => state.globalEnabled);
   }
"
  },
  {
    "file": "packages/features/feature-opt-in/services/FeatureOptInService.ts",
    "line": 161,
    "severity": "high",
    "description": "Policy is hard-coded to 'permissive' instead of being read from the feature configuration. The OptInFeatureConfig interface defines a policy field that should be used. This violates the design pattern where configuration should drive behavior.",
    "fix_patch": "--- a/packages/features/feature-opt-in/services/FeatureOptInService.ts
+++ b/packages/features/feature-opt-in/services/FeatureOptInService.ts
@@ -159,7 +159,7 @@
       userAutoOptIn,
     });

-    const policy: OptInFeaturePolicy = "permissive";
+    const policy = getOptInFeatureConfig(featureId)?.policy ?? "permissive";

     const { enabled: effectiveEnabled, reason: effectiveReason } = computeEffectiveStateAcrossTeams({
"
  },
  {
    "file": "packages/trpc/server/routers/viewer/featureOptIn/_router.ts",
    "line": 95,
    "severity": "medium",
    "description": "setUserState mutation does not validate the slug against the opt-in allowlist before passing it to the service, unlike setTeamState (line 117) and setOrganizationState (line 146). While the service validates via isFeatureAllowedForScope, validating at the API boundary is the established pattern in this router.",
    "fix_patch": "--- a/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
+++ b/packages/trpc/server/routers/viewer/featureOptIn/_router.ts
@@ -95,6 +95,12 @@
     })
     .mutation(async ({ ctx, input }) => {
+      if (!isOptInFeature(input.slug)) {
+        throw new TRPCError({
+          code: "BAD_REQUEST",
+          message: "Invalid slug. This feature is not opt-in configurable.",
+        });
+      }
+
       await featureOptInService.setUserFeatureState({
         userId: ctx.user.id,
         featureId: input.slug,
"
  }
]

